// Enhanced Restaurant booking validation code for n8n
const bookingData = $input.all()[0].json;

// Helper function to convert date from DD/MM/YYYY to YYYY-MM-DD
function convertDateFormat(dateString) {
  const [day, month, year] = dateString.split('/');
  return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
}

// Helper function to create time slots
function createTimeSlots(startTime, endTime, intervalMinutes) {
  const slots = [];
  const [startHour, startMinute] = startTime.split(':').map(Number);
  const [endHour, endMinute] = endTime.split(':').map(Number);

  let currentMinutes = startHour * 60 + startMinute;
  const endMinutes = endHour * 60 + endMinute;

  while (currentMinutes <= endMinutes) {
    const hours = Math.floor(currentMinutes / 60);
    const minutes = currentMinutes % 60;
    slots.push(`${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`);
    currentMinutes += intervalMinutes;
  }

  return slots;
}

// Helper function to check if time is in the past
function isTimePast(dateStr, timeStr) {
  const now = new Date();
  const [hours, minutes] = timeStr.split(':').map(Number);
  const bookingDateTime = new Date(dateStr);
  bookingDateTime.setHours(hours, minutes, 0, 0);

  return bookingDateTime < now;
}

// Helper function to check if a time slot is valid (exists in available slots)
function isValidTimeSlot(requestedTime, availableSlots) {
  return availableSlots.includes(requestedTime);
}

// Helper function to get future slots for today
function getFutureSlots(slots, dateStr) {
  const now = new Date();
  const currentDate = new Date(dateStr);

  if (currentDate.toDateString() === now.toDateString()) {
    const currentHour = now.getHours();
    const currentMinute = now.getMinutes();
    const currentTimeInMinutes = currentHour * 60 + currentMinute;

    return slots.filter(slot => {
      const [hour, minute] = slot.split(':').map(Number);
      const slotTimeInMinutes = hour * 60 + minute;
      return slotTimeInMinutes > currentTimeInMinutes;
    });
  }

  return slots;
}

try {
  // Convert the requested date to YYYY-MM-DD format
  const requestedDate = convertDateFormat(bookingData.date);
  const mealType = bookingData.meal_type.toLowerCase();
  const requestedTime = bookingData.time;
  const tableConfigurations = bookingData.data.table_timings_configurations;
  const timeInterval = parseInt(bookingData.data.table_booking_time_interval);

  // Check if requested date is available
  const availableDate = tableConfigurations.find(config => config.date === requestedDate);

  if (!availableDate) {
    // Return available date options
    const availableDates = tableConfigurations.map(config => ({
      date: config.date,
      day_name: config.day_name,
      lunch_hours: `${config.lunch_open} - ${config.lunch_close}`,
      dinner_hours: `${config.dinner_open} - ${config.dinner_close}`
    }));

    const availableDatesString = availableDates.map(date => 
      `${date.day_name} (${date.date})`
    ).join(', ');

    return [{
      json: {
        status: false,
        message: `Requested date ${bookingData.date} is not available. Please choose from available dates: ${availableDatesString}`,
        available_dates: availableDates,
        should_call_api: 0
      }
    }];
  }

  // Get the appropriate opening and closing times based on meal type
  let openTime, closeTime;

  if (mealType === 'lunch') {
    openTime = availableDate.lunch_open;
    closeTime = availableDate.lunch_close;
  } else if (mealType === 'dinner') {
    openTime = availableDate.dinner_open;
    closeTime = availableDate.dinner_close;
  } else {
    return [{
      json: {
        status: false,
        message: "Invalid meal type. Please specify 'lunch' or 'dinner'.",
        should_call_api: 0
      }
    }];
  }

  // Create time slots
  const timeSlots = createTimeSlots(openTime, closeTime, timeInterval);

  // Get available slots (considering past times for today)
  const availableSlots = getFutureSlots(timeSlots, requestedDate);

  if (availableSlots.length === 0) {
    return [{
      json: {
        status: false,
        message: `No available slots for ${mealType} on ${availableDate.day_name}. Please choose a different date or meal time.`,
        requested_time: requestedTime,
        meal_type: mealType,
        date: requestedDate,
        should_call_api: 0
      }
    }];
  }

  // Check if requested time is in the past
  if (isTimePast(requestedDate, requestedTime)) {
    const availableSlotsString = availableSlots.join(', ');

    return [{
      json: {
        status: false,
        message: `Requested time ${requestedTime} has passed. Here are the available slots for ${mealType} on ${availableDate.day_name}: ${availableSlotsString}. Please choose one of these times.`,
        available_slots: availableSlots,
        meal_type: mealType,
        date: requestedDate,
        requested_time: requestedTime,
        should_call_api: 0,
        awaiting_time_selection: true
      }
    }];
  }

  // Check if requested time is a valid slot
  if (!isValidTimeSlot(requestedTime, availableSlots)) {
    const availableSlotsString = availableSlots.join(', ');

    return [{
      json: {
        status: false,
        message: `Requested time ${requestedTime} is not available for ${mealType} on ${availableDate.day_name}. Here are the available slots: ${availableSlotsString}. Please choose one of these times.`,
        available_slots: availableSlots,
        meal_type: mealType,
        date: requestedDate,
        requested_time: requestedTime,
        should_call_api: 0,
        awaiting_time_selection: true
      }
    }];
  }

  // If we reach here, the requested time is valid and available
  return [{
    json: {
      status: true,
      message: `Booking confirmed for ${bookingData.restaurant_name} on ${availableDate.day_name} (${requestedDate}) at ${requestedTime} for ${bookingData.number_of_people} people.`,
      booking_details: {
        restaurant_name: bookingData.restaurant_name,
        date: requestedDate,
        day_name: availableDate.day_name,
        time: requestedTime,
        meal_type: mealType,
        number_of_people: bookingData.number_of_people,
        special_request: bookingData.special_request,
        requested_time: requestedTime,
        assigned_time: requestedTime,
        meal_hours: mealType === 'lunch' ? `${openTime} - ${closeTime}` : `${openTime} - ${closeTime}`
      },
      available_slots: timeSlots,
      table_booking_time_interval: $input.first().json.data.table_booking_time_interval,
      restaurant_id: $input.first().json.restaurant_id,
      should_call_api: 1
    }
  }];

} catch (error) {
  return [{
    json: {
      status: false,
      message: "An error occurred while processing the booking request.",
      error: error.message,
      should_call_api: 0
    }
  }];
}

